#include <stdio.h>
#include <stdint.h>
#define MOD 1000000009
int64_t dp[5][1000001];
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int K, N;
        scanf("%d %d", &K, &N);
        for (int i = 0; i <= K; i++) {
            for (int j = 0; j <= N; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i <= K; i++) {
            for (int j = 0; j <= N; j++) {
                for (int k = 0; k <= j; k++) {
                    if ((k & j) == k) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][j - k]) % MOD;
                    }
                }
            }
        }
        printf("%lld\n", dp[K][N]);
    }
    return 0;
}

