    let dp = Array(K + 1).fill(0).map(() => Array(N + 1).fill(0));
    dp[0][0] = 1;
    for (let j = 1; j <= K; j++) {
        for (let k = 0; k <= N; k++) {
            for (let l = 0; l <= k; l++) {
                if ((l & k) === l) {
                    dp[j][k] = (dp[j][k] + dp[j - 1][k - l]) % MOD;
                }
            }
        }
    }
    console.log(dp[K][N]);
}

